"""Inventory stock tracker."""


class Stock:
    def __init__(self, sku: str, qty: int = 0):
        self.sku = sku
        self.qty = qty

    def receive(self, n: int) -> None:
        if n < 0:
            raise ValueError("n must be >= 0")
        self.qty += n

    def ship(self, n: int) -> None:
        """Ship n units."""
        if n < 0:
            raise ValueError("n must be >= 0")
        if n > self.qty:
            raise ValueError("insufficient stock")
        self.qty -= n
